-- {"operators": "INNER_JOIN,AGGREGATE,ORDER,WINDOW,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER,OORDER", "ducklake": true}
WITH cust_orders AS (SELECT c.C_W_ID, c.C_D_ID, c.C_ID, c.C_LAST, o.O_ID FROM dl.CUSTOMER c JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID) SELECT C_W_ID, C_ID, C_LAST, COUNT(*) OVER (PARTITION BY C_W_ID, C_D_ID) AS dist_orders, ROW_NUMBER() OVER (PARTITION BY C_W_ID, C_D_ID ORDER BY C_ID) AS rn FROM cust_orders;
